  1→/**
  2→ * Contact API Client
  3→ *
  4→ * TypeScript client for Contact API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on contacts.
  6→ */
  7→
  8→import type {
  9→  ContactData,
 10→  ContactListParams,
 11→  ContactCreateInput,
 12→  ContactUpdateInput,
 13→  ApiListResponse,
 14→  ApiResponse,
 15→  ApiError,
 16→  ApiClientConfig,
 17→} from './types';
 18→
 19→/**
 20→ * Default base URL for API requests
 21→ */
 22→const DEFAULT_BASE_URL = '/api';
 23→
 24→/**
 25→ * API client error class
 26→ */
 27→export class ApiClientError extends Error {
 28→  constructor(
 29→    public statusCode: number,
 30→    public error: string,
 31→    public message: string
 32→  ) {
 33→    super(`${error}: ${message}`);
 34→    this.name = 'ApiClientError';
 35→  }
 36→}
 37→
 38→/**
 39→ * Parse and throw API error from response
 40→ */
 41→async function parseApiError(response: Response): Promise<never> {
 42→  let error: ApiError;
 43→
 44→  try {
 45→    error = await response.json();
 46→  } catch {
 47→    error = {
 48→      error: 'Unknown error',
 49→      message: response.statusText || 'Failed to parse error response',
 50→    };
 51→  }
 52→
 53→  console.error('API request failed:', response.status, error);
 54→  throw new ApiClientError(response.status, error.error, error.message);
 55→}
 56→
 57→/**
 58→ * Validate response is JSON and parse it
 59→ */
 60→async function parseJson<T>(response: Response): Promise<T> {
 61→  const contentType = response.headers.get('content-type');
 62→  if (!contentType?.includes('application/json')) {
 63→    console.error('Unexpected content-type:', contentType);
 64→    throw new ApiClientError(
 65→      response.status,
 66→      'Invalid response',
 67→      'Expected JSON response but got ' + (contentType || 'no content-type')
 68→    );
 69→  }
 70→
 71→  return response.json() as Promise<T>;
 72→}
 73→
 74→/**
 75→ * Contact API Client
 76→ *
 77→ * Provides typed methods for Contact CRUD operations.
 78→ * All methods return typed data or throw ApiClientError.
 79→ */
 80→export class ContactApiClient {
 81→  private baseUrl: string;
 82→  private fetchFn: typeof globalThis.fetch;
 83→  private defaultHeaders: Record<string, string>;
 84→
 85→  constructor(config: ApiClientConfig = {}) {
 86→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 87→    this.fetchFn = config.fetch ?? fetch;
 88→    this.defaultHeaders = {
 89→      'Content-Type': 'application/json',
 90→      ...config.headers,
 91→    };
 92→  }
 93→
 94→  /**
 95→   * Build full URL for endpoint
 96→   */
 97→  private url(path: string, params?: Record<string, string | undefined>): string {
 98→    const fullUrl = `${this.baseUrl}${path}`;
 99→
100→    if (params) {
101→      const searchParams = new URLSearchParams();
102→      for (const [key, value] of Object.entries(params)) {
103→        if (value !== undefined) {
104→          searchParams.append(key, value);
105→        }
106→      }
107→      const queryString = searchParams.toString();
108→      if (queryString) {
109→        return `${fullUrl}?${queryString}`;
110→      }
111→    }
112→
113→    return fullUrl;
114→  }
115→
116→  /**
117→   * GET /api/contacts
118→   *
119→   * List all contacts with optional filtering.
120→   * Supports filtering by type and status.
121→   *
122→   * @returns Array of contacts with count
123→   */
124→  async getContacts(params?: ContactListParams): Promise<ApiListResponse<ContactData>> {
125→    const response = await this.fetchFn(
126→      this.url('/contacts', {
127→        type: params?.type,
128→        status: params?.status,
129→      }),
130→      {
131→        headers: this.defaultHeaders,
132→      }
133→    );
134→
135→    if (!response.ok) {
136→      return parseApiError(response);
137→    }
138→
139→    return parseJson<ApiListResponse<ContactData>>(response);
140→  }
141→
142→  /**
143→   * GET /api/contacts/[id]
144→   *
145→   * Fetch a single contact by ID.
146→   *
147→   * @param id - Contact UUID
148→   * @returns Contact data
149→   * @throws ApiClientError with 404 if not found
150→   */
151→  async getContact(id: string): Promise<ApiResponse<ContactData>> {
152→    if (!id) {
153→      throw new ApiClientError(400, 'Validation failed', 'id is required');
154→    }
155→
156→    const response = await this.fetchFn(this.url(`/contacts/${id}`), {
157→      headers: this.defaultHeaders,
158→    });
159→
160→    if (!response.ok) {
161→      return parseApiError(response);
162→    }
163→
164→    return parseJson<ApiResponse<ContactData>>(response);
165→  }
166→
167→  /**
168→   * POST /api/contacts
169→   *
170→   * Create a new contact.
171→   * Validates required fields based on contact type.
172→   *
173→   * @param data - Contact creation input
174→   * @returns Created contact data
175→   * @throws ApiClientError with 400 on validation errors
176→   */
177→  async createContact(data: ContactCreateInput): Promise<ApiResponse<ContactData>> {
178→    const response = await this.fetchFn(this.url('/contacts'), {
179→      method: 'POST',
180→      headers: this.defaultHeaders,
181→      body: JSON.stringify(data),
182→    });
183→
184→    if (!response.ok) {
185→      return parseApiError(response);
186→    }
187→
188→    return parseJson<ApiResponse<ContactData>>(response);
189→  }
190→
191→  /**
192→   * PUT /api/contacts/[id]
193→   *
194→   * Update an existing contact.
195→   * Only provided fields are updated (partial update).
196→   *
197→   * @param id - Contact UUID
198→   * @param data - Contact update input (all fields optional)
199→   * @returns Updated contact data
200→   * @throws ApiClientError with 404 if contact not found
201→   */
202→  async updateContact(
203→    id: string,
204→    data: ContactUpdateInput
205→  ): Promise<ApiResponse<ContactData>> {
206→    if (!id) {
207→      throw new ApiClientError(400, 'Validation failed', 'id is required');
208→    }
209→
210→    const response = await this.fetchFn(this.url(`/contacts/${id}`), {
211→      method: 'PUT',
212→      headers: this.defaultHeaders,
213→      body: JSON.stringify(data),
214→    });
215→
216→    if (!response.ok) {
217→      return parseApiError(response);
218→    }
219→
220→    return parseJson<ApiResponse<ContactData>>(response);
221→  }
222→
223→  /**
224→   * DELETE /api/contacts/[id]
225→   *
226→   * Soft-delete a contact by setting deletedAt timestamp.
227→   * Contact remains in database but is filtered from queries.
228→   *
229→   * @param id - Contact UUID
230→   * @returns Deleted contact data with success message
231→   * @throws ApiClientError with 404 if contact not found
232→   */
233→  async deleteContact(id: string): Promise<ApiResponse<ContactData> & { message: string }> {
234→    if (!id) {
235→      throw new ApiClientError(400, 'Validation failed', 'id is required');
236→    }
237→
238→    const response = await this.fetchFn(this.url(`/contacts/${id}`), {
239→      method: 'DELETE',
240→      headers: this.defaultHeaders,
241→    });
242→
243→    if (!response.ok) {
244→      return parseApiError(response);
245→    }
246→
247→    return parseJson<ApiResponse<ContactData> & { message: string }>(response);
248→  }
249→}
