251→/**
252→ * Default singleton instance for use across the application
253→ */
254→export const contactsApi = new ContactApiClient();
255→
256→/**
257→ * Convenience exports for direct use
258→ */
259→export const {
260→  getContacts,
261→  getContact,
262→  createContact,
263→  updateContact,
264→  deleteContact,
265→} = contactsApi;
266→
267→export default contactsApi;
